#include <bits/stdc++.h>
using namespace std;
const int maxn=1e2+5;
int n,a[maxn],s[maxn],dp[maxn][maxn],ans=-1,root[maxn][maxn];
void out(int l,int r){
	if(l>r){
		return ;
	}
	cout<<root[l][r]<<" ";
	if(l==r){
		return ;
	}
	out(l,root[l][r]-1);
	out(root[l][r]+1,r);
}
int main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>a[i];
		s[i]=s[i-1]+a[i];
	}
	for(int i=1;i<=n;i++) dp[i][i]=a[i],root[i][i]=i;
	for(int i=2;i<=n;i++){
		for(int j=1;j<=n;j++){
			int S=i+j-1;
			if(S>n){
				continue;
			}
			dp[j][S]=s[S]-s[j-1];
			root[j][S]=j;
			for(int k=j+1;k<S;k++){
				int aa=dp[j][k-1]*dp[k+1][S]+a[k];
				if(aa>dp[j][S]){
					dp[j][S]=aa;
					root[j][S]=k;
				}
			}
		}
	}
	cout<<dp[1][n]<<"\n";
	out(1,n);
	return 0;
}
